      delta.forEach(spy);
      expect(spy.calls.count()).toEqual(3);
    });

    it('map()', () => {
      const arr = delta.map((op) => {
        return typeof op.insert === 'string' ? op.insert : '';
      });
      expect(arr).toEqual(['Hello', '', 'World!']);
    });

    it('partition()', () => {
      const arr = delta.partition((op) => {
        return typeof op.insert === 'string';
